mapper.select:
SELECT r.record_id, r.plate_number, r.space_id, r.entry_time, r.entry_gate, r.exit_time, r.exit_gate, r.parking_minutes, r.fee_amount, r.payable_amount, r.paid_amount, r.pay_status, r.pay_time, r.pay_method, r.status, s.space_code, a.area_code, a.area_name FROM parking_record r INNER JOIN parking_space s ON r.space_id = s.space_id INNER JOIN parking_area a ON s.area_id = a.area_id
AND r.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND r.status = #{status}
AND r.pay_status = #{payStatus}
ORDER BY r.entry_time DESC
